CES asset_models(id));\n+CREATE TABLE IF NOT EXISTS tickets(id TEXT PRIMARY KEY,type TEXT NOT NULL,requester_id INTEGER NOT NULL,department_id TEXT,asset_id TEXT,model_id TEXT,to_user_id INTEGER,status TEXT NOT NULL,priority TEXT NOT NULL DEFAULT 'normal',title TEXT NOT NULL,description TEXT,ai_result TEXT,manager_decision TEXT,it_decision TEXT,created_at TEXT NOT NULL,updated_at TEXT NOT NULL);\n+CREATE TABLE IF NOT EXISTS ticket_events(id INTEGER PRIMARY KEY AUTOINCREMENT,ticket_id TEXT NOT NULL,actor_id INTEGER,event TEXT NOT NULL,note TEXT,created_at TEXT NOT NULL);\n+CREATE TABLE IF NOT EXISTS asset_events(id INTEGER PRIMARY KEY AUTOINCREMENT,asset_id TEXT NOT NULL,actor_id INTEGER,event TEXT NOT NULL,from_status TEXT,to_status TEXT,note TEXT,ticket_id TEXT,created_at TEXT NOT NULL);\n+CREATE TABLE IF NOT EXISTS notifications(id TEXT PRIMARY KEY,user_id INTEGER NOT NULL,title TEXT NOT NULL,body TEXT NOT NULL,link TEXT,read_at TEXT,created_at TEXT NOT NULL);\n+CREATE TABLE IF NOT EXISTS audit_logs(id INTEGER PRIMARY KEY AUTOINCREMENT,actor_id INTEGER,action TEXT NOT NULL,entity_type TEXT NOT NULL,entity_id TEXT,detail TEXT,created_at TEXT NOT NULL);`);\n+  if (get(\"SELECT COUNT(*) AS c FROM users\").c > 0 && !reset) return;\n+  await seedDb();\n+}\n+\n+async function seedDb() {\n+  run(`DELETE FROM audit_logs; DELETE FROM notifications; DELETE FROM asset_events; DELETE FROM ticket_events; DELETE FROM tickets; DELETE FROM assets; DELETE FROM asset_models; DELETE FROM users; DELETE FROM departments;`);\n+  run(`INSERT INTO departments(id,name,manager_id) VALUES\n+('DEPT-01','研发部',3),('DEPT-02','产品部',4),('DEPT-03','运营部',NULL),('DEPT-04','IT部',5),('DEPT-05','总办',6);\n+INSERT INTO users(id,email,password,name,role,department_id,active) VALUES\n+(1,'employee1@company.com','password','员工甲','employee','DEPT-01',1),\n+(2,'employee2@company.com','password','员工乙','employee','DEPT-02',1),\n+(3,'manager1@company.com','password','主管甲','manager','DEPT-01',1),\n+(4,'manager2@company.com','password','主管乙','manager','DEPT-02',1),\n+(5,'admin@company.com','password','管理员','it','DEPT-04',1),\n+(6,'exec@company.com','password','高管','exec','DEPT-05',1),\n+(7,'employee3@company.com','password','员工丙','employee','DEPT-01',1),\n+(8,'employee4@company.com','password','员工丁','employee','DEPT-02',1),\n+(9,'ops1@company.com','password','运营甲','employee','DEPT-03',1),\n+(10,'ops2@company.com','password','运营乙','employee','DEPT-03',1);\n+INSERT INTO asset_models(id,name,category,brand,specs,purchase_price,warranty_months,min_stock,supplier,keywords,active) VALUES\n+('MODEL-L01','MacBook Pro M3 14寸','laptop','Apple','M3 Pro / 36GB / 1TB / 14寸 Liquid Retina',16000,12,2,'Apple 经销商','视频剪辑 设计 前端 移动 高性能 笔记本',1),\n+('MODEL-L02','ThinkPad X1 Carbon','laptop','Lenovo','i7 / 32GB / 1TB / 14寸 / 轻薄',12000,36,3,'联想授权','开发 docker ide 后端 轻薄 高性能 笔记本',1),\n+('MODEL-L03','Dell XPS 15 独显版','laptop','Dell','i9 / 32GB / 1TB / RTX 独显 / 15寸',14000,24,2,'Dell 企业','3D 建模 显卡 独显 渲染 高性能 笔记本',1),\n+('MODEL-M01','Dell U2722D 27寸 4K','monitor','Dell','27寸 / 4K / USB-C / 可升降',3200,36,3,'Dell 企业','显示器 屏幕 外接 4k 设计',1),\n+('MODEL-K01','罗技 MX Keys S 无线','keyboard','Logitech','无线 / 蓝牙 / 深灰 / 背光',699,24,4,'罗技代理','键盘 外设 蓝牙 无线',1);\n+INSERT INTO assets(id,serial_no,model_id,holder_id,department_id,status,purchase_date,warranty_until,location,supplier) VALUES\n+('AST-101','SN-101','MODEL-L01',NULL,NULL,'in_stock','2026-04-20','2027-04-20','IT 待验收区','Apple 经销商'),\n+('AST-102','SN-102','MODEL-L01',NULL,NULL,'available','2026-04-01','2027-04-01','IT 仓库','Apple 经销商'),\n+('AST-103','SN-103','MODEL-M01',1,'DEPT-01','assigned','2026-03-10','2029-03-10','IT 前台','Dell 企业'),\n+('AST-104','SN-104','MODEL-L01',2,'DEPT-02','in_use','2026-02-01','2027-12-01','产品工位 B2','Apple 经销商'),\n+('AST-105','SN-105','MODEL-L01',1,'DEPT-01','returning','2025-12-20','2026-12-20','研发工位 A1','Apple 经销商'),\n+('AST-106','SN-106','MODEL-M01',2,'DEPT-02','repairing','2025-11-10','2028-11-10','维修架','Dell 企业'),\n+('AST-107','SN-107','MODEL-L02',3,'DEPT-01','transferring','2025-10-02','2028-10-02','研发工位 A3','联想授权'),\n+('AST-108','SN-108','MODEL-M01',NULL,NULL,'scrapped','2024-01-08','2027-01-08','报废区','Dell 企业'),\n+('AST-109','SN-109','MODEL-K01',NULL,NULL,'lost','2024-02-08','2026-02-08','未知','罗技代理'),\n+('AST-110','SN-110','MODEL-K01',NULL,NULL,'available','2026-04-25','2028-04-25','IT 仓库','罗技代理'),\n+('AST-111','SN-111','MODEL-L02',1,'DEPT-01','in_use','2025-05-01','2028-05-01','研发工位 A1','联想授权'),\n+('AST-112','SN-112','MODEL-L03',NULL,NULL,'available','2026-01-15','2028-01-15','IT 仓库','Dell 企业'),\n+('AST-113','SN-113','MODEL-L03',7,'DEPT-01','in_use','2025-09-15','2027-09-15','研发工位 A4','Dell 企业'),\n+('AST-114','SN-114','MODEL-M01',NULL,NULL,'available','2026-02-10','2029-02-10','IT 仓库','Dell 企业'),\n+('AST-115','SN-115','MODEL-K01',1,'DEPT-01','in_use','2026-03-12','2028-03-12','研发工位 A1','罗技代理'),\n+('AST-116','SN-116','MODEL-K01',NULL,NULL,'available','2026-03-12','2028-03-12','IT 仓库','罗技代理'),\n+('AST-117','SN-117','MODEL-L02',8,'DEPT-02','in_use','2024-08-12','2027-08-12','产品工位 B4','联想授权'),\n+('AST-118','SN-118','MODEL-L03',NULL,NULL,'scrapped','2023-07-01','2025-07-01','报废区','Dell 企业'),\n+('AST-119','SN-119','MODEL-M01',9,'DEPT-03','in_use','2024-05-20','2027-05-20','运营工位 C1','Dell 企业'),\n+('AST-120','SN-120','MODEL-L02',10,'DEPT-03','in_use','2024-09-22','2027-09-22','运营工位 C2','联想授权');\n+INSERT INTO tickets(id,type,requester_id,department_id,asset_id,model_id,to_user_id,status,priority,title,description,ai_result,created_at,updated_at) VALUES\n+('TKT-A01','apply',1,'DEPT-01',NULL,'MODEL-L01',NULL,'pending_manager','normal','申领 MacBook Pro M3 14寸','开发测试需要','{\"reason\":\"高价值设备需主管审批\"}',${q(now())},${q(now())}),\n+('TKT-A02','apply',2,'DEPT-02',NULL,'MODEL-L02',NULL,'pending_it','normal','申领 ThinkPad X1 Carbon','产品演示需要','{\"reason\":\"轻薄笔记本\"}',${q(now())},${q(now())}),\n+('TKT-R01','repair',2,'DEPT-02','AST-106',NULL,NULL,'pending_it','high','报修 AST-106','屏幕花屏','{\"category\":\"hardware\",\"severity\":\"high\",\"need_repair\":true}',${q(now())},${q(now())}),\n+('TKT-T01','transfer',5,'DEPT-01','AST-107',NULL,4,'transferring','normal','调拨 AST-107','跨部门调拨','',${q(now())},${q(now())}),\n+('TKT-RET-01','return',1,'DEPT-01','AST-105',NULL,NULL,'returning','normal','归还 AST-105','离职归还','',${q(now())},${q(now())});\n+INSERT INTO notifications(id,user_id,title,body,link,created_at) VALUES\n+('MSG-001',1,'[可领取设备] 你的设备已准备好','请前往 IT 前台领取设备。','/tickets/TKT-A02',${q(now())}),\n+('MSG-002',3,'[待审批] 员工甲申请了一台 MacBook Pro M3 14寸','请及时处理申领工单 TKT-A01。','/tickets/TKT-A01',${q(now())}),\n+('MSG-003',2,'[保修即将到期] 你持有的 MacBook Pro M3 即将过保','设备 AST-104 将于 2027-12-01 过保。','/assets/AST-104',${q(now())});`);\n+  for (const asset of all(\"SELECT id,status FROM assets\")) addAssetEvent(asset.id, null, \"seed\", null, asset.status, \"初始化资产状态\");\n+  for (const ticket of all(\"SELECT id,status FROM tickets\")) addTicketEvent(ticket.id, null, \"seed\", `初始化工单状态 ${ticket.status}`);\n+  audit(null, \"seed\", \"system\", \"init\", \"初始化比赛数据\");\n+}\n+\n+async function callLLM(task, input, context) {\n+  const base = process.env.AI_API_BASE_URL;\n+  const key = process.env.AI_API_KEY;\n+  if (!base || !key) return null;\n+  const controller = new AbortController();\n+  const timeout = setTimeout(() => controller.abort(), 5000);\n+  try {\n+    const res = await fetch(`${base.replace(/\\/$/, \"\")}/chat/completions`, {\n+      method: \"POST\",\n+      signal: controller.signal,\n+      headers: { \"Content-Type\": \"application/json\", Authorization: `Bearer ${key}` },\n+      body: JSON.stringify({\n+        model: process.env.AI_MODEL || \"deepseek-chat\",\n+        temperature: 0.2,\n+        messages: [\n+          { role: \"system\", content: \"你是 IT 资产管理系统助手。输出简洁中文。任何状态变更必须要求用户二次确认。\" },\n+          { role: \"user\", content: JSON.stringify({ task, input, context }) }\n+        ]\n+      })\n+    });\n+    if (!res.ok) return null;\n+    const data = await res.json();\n+    return data.choices?.[0]?.message?.content || null;\n+  } catch {\n+    return null;\n+  } finally {\n+    clearTimeout(timeout);\n+  }\n+}\n+\n+function fallbackRecommend(text, user) {\n+  const words = String(text || \"\").toLowerCase();\n+  const models = all(`SELECT m.*, (SELECT COUNT(*) FROM assets a WHERE a.model_id=m.id AND a.status='available') AS available_count FROM asset_models m WHERE active=1`);\n+  const scored = models.map(model => {\n+    let score = 0.25;\n+    const corpus = `${model.name} ${model.category} ${model.brand} ${model.specs} ${model.keywords}`.toLowerCase();\n+    for (const token of words.split(/[\\s,，。;；]+/)) if (token && corpus.includes(token)) score += 0.1;\n+    if (/3d|建模|显卡|独显|渲染/.test(words) && model.id === \"MODEL-L03\") score += 0.55;\n+    if (/docker|开发|ide|后端|编程/.test(words) && model.id === \"MODEL-L02\") score += 0.55;\n+    if (/视频|剪辑|设计|移动/.test(words) && model.id === \"MODEL-L01\") score += 0.45;\n+    if (/显示|屏幕|外接|4k/.test(words) && model.category === \"monitor\") score += 0.5;\n+    if (/键盘|外设/.test(words) && model.category === \"keyboard\") score += 0.5;\n+    return {\n+      ...modelDto(model, user),\n+      score: Math.min(1, Number(score.toFixed(2))),\n+      reason: `${model.name} 与需求关键词匹配，${model.available_count > 0 ? `当前可用 ${model.available_count} 台` : \"当前暂无库存，可联系 IT 补货\"}。`\n+    };\n+  }).sort((a, b) => b.score - a.score || b.available_count - a.available_count);\n+  return scored.slice(0, 3);\n+}\n+\n+function fallbackTriage(text) {\n+  const value = String(text || \"\");\n+  const hardware = /屏幕|黑屏|不亮|无法开机|开不了机|进水|摔|花屏|电池|充电|硬盘|键盘坏/.test(value);\n+  const softwareLow = /慢|卡|软件|更新|崩溃|弹窗|空间/.test(value) && !hardware;\n+  if (hardware) {\n+    return { category: \"hardware\", severity: \"high\", need_repair: true, reason: \"描述涉及关键硬件或无法开机，严重影响工作。\", self_help: \"\" };\n+  }\n+  if (softwareLow) {\n+    return { category: \"software\", severity: \"low\", need_repair: false, reason: \"更像软件或性能问题，可先自助排查。\", self_help: \"请先重启设备、关闭高占用程序、释放磁盘空间并安装系统更新；仍未解决可坚持报修。\" };\n+  }\n+  return { category: \"user_error\", severity: \"low\", need_repair: false, reason: \"暂未发现硬件损坏迹象。\", self_help: \"请补充故障截图、出现时间和影响范围，或联系 IT 协助确认。\" };\n+}\n+\n+const routes = [];\n+function route(method, pattern, handler) {\n+  const keys = [];\n+  const regex = new RegExp(`^${pattern.replace(/:([^/]+)/g, (_, key) => {\n+    keys.push(key);\n+    return \"([^/]+)\";\n+  })}$`);\n+  routes.push({ method, regex, keys, handler });\n+}\n+\n+route(\"POST\", \"/api/test/reset\", async (_req, res) => {\n+  await initDb({ reset: true });\n+  json(res, 200, { ok: true });\n+});\n+\n+route(\"POST\", \"/api/login\", async (req, res) => {\n+  const b = await body(req);\n+  const user = get(`SELECT u.*, d.name AS department_name FROM users u LEFT JOIN departments d ON d.id=u.department_id WHERE email=${q(b.email)} AND password=${q(b.password)} AND active=1`);\n+  if (!user) return json(res, 401, { error: \"账号或密码错误\" });\n+  audit(user.id, \"login\", \"user\", user.id, \"用户登录\");\n+  json(res, 200, { user: publicUser(user) });\n+});\n+\n+route(\"GET\", \"/api/me\", async (_req, res, user) => {\n+  requireAuth(user);\n+  json(res, 200, { user: publicUser(user) });\n+});\n+\n+route(\"GET\", \"/api/summary\", async (_req, res, user) => {\n+  requireAuth(user);\n+  const myAssets = get(`SELECT COUNT(*) AS c FROM assets WHERE holder_id=${q(user.id)} AND status IN ('assigned','in_use','returning','repairing','transferring')`).c;\n+  const myTickets = get(`SELECT COUNT(*) AS c FROM tickets WHERE requester_id=${q(user.id)} OR to_user_id=${q(user.id)}`).c;\n+  const unread = get(`SELECT COUNT(*) AS c FROM notifications WHERE user_id=${q(user.id)} AND read_at IS NULL`).c;\n+  const pending = user.role === \"manager\"\n+    ? get(`SELECT COUNT(*) AS c FROM tickets WHERE status='pending_manager' AND department_id=${q(user.department_id)} AND requester_id != ${q(user.id)}`).c\n+    : user.role === \"it\"\n+      ? get(`SELECT COUNT(*) AS c FROM tickets WHERE status IN ('pending_it','returning','repairing','transferring','approved')`).c\n+      : 0;\n+  json(res, 200, { myAssets, myTickets, unread, pending });\n+});\n+\n+route(\"GET\", \"/api/assets\", async (req, res, user) => {\n+  requireAuth(user);\n+  const params = new URL(req.url, \"http://local\").searchParams;\n+  let where = \"1=1\";\n+  if (user.role === \"employee\") where += ` AND a.holder_id=${q(user.id)}`;\n+  if (user.role === \"manager\") where += params.get(\"dept\") === \"1\" ? ` AND a.department_id=${q(user.department_id)}` : ` AND a.holder_id=${q(user.id)}`;\n+  if (user.role === \"exec\") throw error(403, \"管理层只能查看聚合看板\");\n+  if (params.get(\"status\")) where += ` AND a.status=${q(params.get(\"status\"))}`;\n+  const rows = all(`SELECT a.*, m.name AS model_name, m.category, m.specs, m.purchase_price, u.name AS holder_name, d.name AS department_name\n+FROM assets a JOIN asset_models m ON m.id=a.model_id LEFT JOIN users u ON u.id=a.holder_id LEFT JOIN departments d ON d.id=a.department_id\n+WHERE ${where} ORDER BY a.id`);\n+  json(res, 200, { assets: rows.map(asset => assetDto(asset, user)) });\n+});\n+\n+route(\"GET\", \"/api/assets/:id\", async (_req, res, user, p) => {\n+  requireAuth(user);\n+  const asset = get(`SELECT a.*, m.name AS model_name, m.category, m.specs, m.purchase_price, u.name AS holder_name, d.name AS department_name\n+FROM assets a JOIN asset_models m ON m.id=a.model_id LEFT JOIN users u ON u.id=a.holder_id LEFT JOIN departments d ON d.id=a.department_id WHERE a.id=${q(p.id)}`);\n+  if (!asset) return json(res, 404, { error: \"资产不存在\" });\n+  if (!canViewAsset(user, asset)) throw error(403, \"你无权查看该资产\");\n+  const events = all(`SELECT e.*, u.name AS actor_name FROM asset_events e LEFT JOIN users u ON u.id=e.actor_id WHERE e.asset_id=${q(p.id)} ORDER BY e.id ASC`);\n+  json(res, 200, { asset: assetDto(asset, user), events });\n+});\n+\n+route(\"GET\", \"/api/models\", async (_req, res, user) => {\n+  requireAuth(u