r_id,department_id,asset_id,status,priority,title,description,created_at,updated_at) VALUES(${q(id)},'return',${q(user.id)},${q(user.department_id)},${q(asset.id)},'returning','normal',${q(`归还 ${asset.id}`)},${q(b.reason || \"\")},${q(now())},${q(now())})`,\n+    `INSERT INTO asset_events(asset_id,actor_id,event,from_status,to_status,note,ticket_id,created_at) VALUES(${q(asset.id)},${q(user.id)},'return_requested','in_use','returning',${q(b.reason || \"\")},${q(id)},${q(now())})`,\n+    `INSERT INTO ticket_events(ticket_id,actor_id,event,note,created_at) VALUES(${q(id)},${q(user.id)},'created','员工提交归还',${q(now())})`\n+  ]);\n+  audit(user.id, \"ticket.return.create\", \"ticket\", id, asset.id);\n+  notify(5, `[待确认归还] ${user.name} 提交了归还工单`, `资产 ${asset.id} 等待 IT 接收。`, `/tickets/${id}`);\n+  json(res, 201, { ticket: get(`SELECT * FROM tickets WHERE id=${q(id)}`) });\n+});\n+\n+route(\"POST\", \"/api/tickets/repair\", async (req, res, user) => {\n+  requireAuth(user);\n+  const b = await body(req);\n+  const asset = get(`SELECT * FROM assets WHERE id=${q(b.asset_id)} AND holder_id=${q(user.id)} AND status='in_use'`);\n+  if (!asset) throw error(400, \"只能报修自己正在使用的资产\");\n+  const triage = b.triage || fallbackTriage(b.description || \"\");\n+  if (!triage.need_repair && !b.force) {\n+    return json(res, 200, { created: false, triage, message: \"建议先按自助方案排查；如仍需报修，请选择坚持报修。\" });\n+  }\n+  const id = makeTicketId(\"TKT-R\");\n+  tx([\n+    `UPDATE assets SET status='repairing' WHERE id=${q(asset.id)}`,\n+    `INSERT INTO tickets(id,type,requester_id,department_id,asset_id,status,priority,title,description,ai_result,created_at,updated_at) VALUES(${q(id)},'repair',${q(user.id)},${q(user.department_id)},${q(asset.id)},'pending_it',${q(triage.severity === \"high\" ? \"high\" : \"normal\")},${q(`报修 ${asset.id}`)},${q(b.description || \"\")},${q(JSON.stringify(triage))},${q(now())},${q(now())})`,\n+    `INSERT INTO asset_events(asset_id,actor_id,event,from_status,to_status,note,ticket_id,created_at) VALUES(${q(asset.id)},${q(user.id)},'repair_requested','in_use','repairing',${q(b.description || \"\")},${q(id)},${q(now())})`,\n+    `INSERT INTO ticket_events(ticket_id,actor_id,event,note,created_at) VALUES(${q(id)},${q(user.id)},'created','员工提交报修',${q(now())})`\n+  ]);\n+  audit(user.id, \"ticket.repair.create\", \"ticket\", id, JSON.stringify(triage));\n+  notify(5, \"[维修工单] 有新的维修请求\", `${user.name} 报修 ${asset.id}`, `/tickets/${id}`);\n+  json(res, 201, { created: true, ticket: get(`SELECT * FROM tickets WHERE id=${q(id)}`), triage });\n+});\n+\n+route(\"POST\", \"/api/tickets/:id/complete\", async (req, res, user, p) => {\n+  requireRole(user, [\"it\"]);\n+  const b = await body(req);\n+  const ticket = get(`SELECT * FROM tickets WHERE id=${q(p.id)}`);\n+  if (!ticket || [\"completed\", \"cancelled\", \"rejected\"].includes(ticket.status)) throw error(400, \"工单不存在或已结束\");\n+  const asset = get(`SELECT * FROM assets WHERE id=${q(ticket.asset_id)}`);\n+  let nextStatus = \"available\";\n+  let holderExpr = \"NULL\";\n+  let deptExpr = \"NULL\";\n+  if (ticket.type === \"repair\" && b.result !== \"stock\") {\n+    nextStatus = b.result === \"scrap\" ? \"scrapped\" : \"in_use\";\n+    holderExpr = nextStatus === \"in_use\" ? q(ticket.requester_id) : \"NULL\";\n+    deptExpr = nextStatus === \"in_use\" ? q(ticket.department_id) : \"NULL\";\n+  }\n+  if (ticket.type === \"return\" && b.result === \"scrap\") nextStatus = \"scrapped\";\n+  tx([\n+    `UPDATE assets SET status=${q(nextStatus)}, holder_id=${holderExpr}, department_id=${deptExpr}, scrap_reason=${q(nextStatus === \"scrapped\" ? b.note || \"无法继续使用\" : null)} WHERE id=${q(asset.id)}`,\n+    `UPDATE tickets SET status='completed', updated_at=${q(now())} WHERE id=${q(ticket.id)}`,\n+    `INSERT INTO asset_events(asset_id,actor_id,event,from_status,to_status,note,ticket_id,created_at) VALUES(${q(asset.id)},${q(user.id)},${q(ticket.type === \"repair\" ? \"repair_completed\" : \"return_completed\")},${q(asset.status)},${q(nextStatus)},${q(b.note || \"\")},${q(ticket.id)},${q(now())})`,\n+    `INSERT INTO ticket_events(ticket_id,actor_id,event,note,created_at) VALUES(${q(ticket.id)},${q(user.id)},'completed',${q(b.note || \"\")},${q(now())})`\n+  ]);\n+  audit(user.id, \"ticket.complete\", \"ticket\", ticket.id, b.note || \"\");\n+  notify(ticket.requester_id, ticket.type === \"repair\" ? \"[维修进度] 你的设备维修状态已更新\" : \"[归还已完成] IT 已确认接收\", b.note || \"处理完成\", `/tickets/${ticket.id}`);\n+  json(res, 200, { ticket: get(`SELECT * FROM tickets WHERE id=${q(ticket.id)}`), asset: get(`SELECT * FROM assets WHERE id=${q(asset.id)}`) });\n+});\n+\n+route(\"POST\", \"/api/tickets/transfer\", async (req, res, user) => {\n+  requireRole(user, [\"it\"]);\n+  const b = await body(req);\n+  const asset = get(`SELECT * FROM assets WHERE id=${q(b.asset_id)}`);\n+  if (!asset) throw error(404, \"资产不存在\");\n+  if (asset.status !== \"in_use\") throw error(400, \"只有使用中的资产可以调拨\");\n+  const toUser = get(`SELECT * FROM users WHERE id=${q(b.to_user_id)} AND active=1`);\n+  if (!toUser) throw error(400, \"接收人不存在\");\n+  const id = makeTicketId(\"TKT-T\");\n+  tx([\n+    `UPDATE assets SET status='transferring' WHERE id=${q(asset.id)}`,\n+    `INSERT INTO tickets(id,type,requester_id,department_id,asset_id,to_user_id,status,priority,title,description,created_at,updated_at) VALUES(${q(id)},'transfer',${q(user.id)},${q(asset.department_id)},${q(asset.id)},${q(toUser.id)},'pending_manager','normal',${q(`调拨 ${asset.id}`)},${q(b.reason || \"\")},${q(now())},${q(now())})`,\n+    `INSERT INTO asset_events(asset_id,actor_id,event,from_status,to_status,note,ticket_id,created_at) VALUES(${q(asset.id)},${q(user.id)},'transfer_requested','in_use','transferring',${q(b.reason || \"\")},${q(id)},${q(now())})`\n+  ]);\n+  audit(user.id, \"ticket.transfer.create\", \"ticket\", id, asset.id);\n+  json(res, 201, { ticket: get(`SELECT * FROM tickets WHERE id=${q(id)}`) });\n+});\n+\n+route(\"POST\", \"/api/tickets/:id/execute-transfer\", async (req, res, user, p) => {\n+  requireRole(user, [\"it\"]);\n+  const b = await body(req);\n+  const ticket = get(`SELECT * FROM tickets WHERE id=${q(p.id)} AND type='transfer'`);\n+  if (!ticket || ![\"transferring\", \"pending_manager\"].includes(ticket.status)) throw error(400, \"当前调拨工单不可执行\");\n+  const asset = get(`SELECT * FROM assets WHERE id=${q(ticket.asset_id)}`);\n+  if (!asset || asset.status !== \"transferring\") throw error(400, \"资产不在调拨中\");\n+  const toUser = get(`SELECT * FROM users WHERE id=${q(ticket.to_user_id)}`);\n+  tx([\n+    `UPDATE assets SET status='in_use', holder_id=${q(toUser.id)}, department_id=${q(toUser.department_id)} WHERE id=${q(asset.id)}`,\n+    `UPDATE tickets SET status='completed', updated_at=${q(now())} WHERE id=${q(ticket.id)}`,\n+    `INSERT INTO asset_events(asset_id,actor_id,event,from_status,to_status,note,ticket_id,created_at) VALUES(${q(asset.id)},${q(user.id)},'transfer_completed','transferring','in_use',${q(b.note || \"\")},${q(ticket.id)},${q(now())})`,\n+    `INSERT INTO ticket_events(ticket_id,actor_id,event,note,created_at) VALUES(${q(ticket.id)},${q(user.id)},'completed','IT 执行调拨',${q(now())})`\n+  ]);\n+  audit(user.id, \"ticket.transfer.execute\", \"ticket\", ticket.id, asset.id);\n+  json(res, 200, { ticket: get(`SELECT * FROM tickets WHERE id=${q(ticket.id)}`), asset: get(`SELECT * FROM assets WHERE id=${q(asset.id)}`) });\n+});\n+\n+route(\"POST\", \"/api/inbound\", async (req, res, user) => {\n+  requireRole(user, [\"it\"]);\n+  const b = await body(req);\n+  if (get(`SELECT id FROM assets WHERE id=${q(b.asset_id)}`)) throw error(409, \"资产编号已存在\");\n+  if (b.serial_no && get(`SELECT id FROM assets WHERE serial_no=${q(b.serial_no)}`)) throw error(409, \"序列号已存在\");\n+  const model = get(`SELECT * FROM asset_models WHERE id=${q(b.model_id)}`);\n+  if (!model) throw error(400, \"型号不存在\");\n+  tx([\n+    `INSERT INTO assets(id,serial_no,model_id,status,purchase_date,warranty_until,location,supplier) VALUES(${q(b.asset_id)},${q(b.serial_no || \"\")},${q(model.id)},'available',${q(b.purchase_date)},${q(b.warranty_until)},${q(b.location || \"IT 仓库\")},${q(b.supplier || model.supplier)})`,\n+    `INSERT INTO asset_events(asset_id,actor_id,event,from_status,to_status,note,created_at) VALUES(${q(b.asset_id)},${q(user.id)},'inbound',NULL,'available','扫码/手动入库',${q(now())})`,\n+    `INSERT INTO audit_logs(actor_id,action,entity_type,entity_id,detail,created_at) VALUES(${q(user.id)},'asset.inbound','asset',${q(b.asset_id)},${q(model.name)},${q(now())})`\n+  ]);\n+  json(res, 201, { asset: get(`SELECT * FROM assets WHERE id=${q(b.asset_id)}`) });\n+});\n+\n+route(\"POST\", \"/api/inventory/scan\", async (req, res, user) => {\n+  requireRole(user, [\"it\"]);\n+  const b = await body(req);\n+  const codes = Array.isArray(b.asset_ids) ? b.asset_ids : String(b.asset_ids || b.asset_nos || \"\").split(/[,\\n\\r\\t ]+/).filter(Boolean);\n+  const assets = all(\"SELECT id,status FROM assets\");\n+  const known = new Set(assets.map(a => a.id));\n+  const scanned = new Set(codes);\n+  const missing = assets.filter(a => !scanned.has(a.id) && !TERMINAL_ASSET_STATES.has(a.status)).map(a => a.id);\n+  const unknown = [...scanned].filter(id => !known.has(id));\n+  audit(user.id, \"inventory.scan\", \"inventory\", \"scan\", `scanned=${codes.length}`);\n+  json(res, 200, { scanned: codes.length, matched: [...scanned].filter(id => known.has(id)), missing, unknown });\n+});\n+\n+route(\"GET\", \"/api/users\", async (_req, res, user) => {\n+  requireRole(user, [\"it\", \"exec\"]);\n+  const rows = all(`SELECT u.id,u.email,u.name,u.role,u.department_id,u.active,d.name AS department_name,(SELECT COUNT(*) FROM assets a WHERE a.holder_id=u.id AND a.status IN ('assigned','in_use','returning','repairing','transferring')) AS asset_count FROM users u LEFT JOIN departments d ON d.id=u.department_id ORDER BY u.id`);\n+  json(res, 200, { users: rows });\n+});\n+\n+route(\"POST\", \"/api/users/:id/offboard\", async (_req, res, user, p) => {\n+  requireRole(user, [\"it\"]);\n+  run(`UPDATE users SET active=0 WHERE id=${q(p.id)}`);\n+  const unreturned = all(`SELECT id, status FROM assets WHERE holder_id=${q(p.id)} AND status IN ('assigned','in_use','returning','repairing','transferring')`);\n+  audit(user.id, \"user.offboard\", \"user\", p.id, `未归还 ${unreturned.map(a => a.id).join(\",\")}`);\n+  json(res, 200, { ok: true, unreturned });\n+});\n+\n+route(\"GET\", \"/api/notifications\", async (_req, res, user) => {\n+  requireAuth(user);\n+  json(res, 200, { notifications: all(`SELECT * FROM notifications WHERE user_id=${q(user.id)} ORDER BY created_at DESC`) });\n+});\n+\n+route(\"POST\", \"/api/notifications/:id/read\", async (_req, res, user, p) => {\n+  requireAuth(user);\n+  run(`UPDATE notifications SET read_at=${q(now())} WHERE id=${q(p.id)} AND user_id=${q(user.id)}`);\n+  json(res, 200, { ok: true });\n+});\n+\n+route(\"GET\", \"/api/audit\", async (_req, res, user) => {\n+  requireRole(user, [\"it\"]);\n+  json(res, 200, { logs: all(`SELECT l.*, u.name AS actor_name FROM audit_logs l LEFT JOIN users u ON u.id=l.actor_id ORDER BY l.id DESC LIMIT 300`) });\n+});\n+\n+route(\"GET\", \"/api/exec/dashboard\", async (_req, res, user) => {\n+  requireRole(user, [\"it\", \"exec\"]);\n+  const assets = all(`SELECT a.*, m.purchase_price, m.name AS model_name, m.category, d.name AS department_name FROM assets a JOIN asset_models m ON m.id=a.model_id LEFT JOIN departments d ON d.id=a.department_id`);\n+  const activeAssets = assets.filter(a => !TERMINAL_ASSET_STATES.has(a.status));\n+  const net = activeAssets.reduce((sum, asset) => sum + netValue(asset), 0);\n+  const byDept = all(`SELECT COALESCE(d.name,'库存/未分配') AS name, COUNT(*) AS count FROM assets a LEFT JOIN departments d ON d.id=a.department_id WHERE a.status NOT IN ('scrapped','lost') GROUP BY COALESCE(d.name,'库存/未分配')`);\n+  const lowStock = all(`SELECT m.id,m.name,m.min_stock,(